async (params, browser) => {
  // Open Todoist
  await browser.open('https://app.todoist.com/app/today')

  // Wait for app to load
  await browser.waitForSelector('main, [class*="task"], .content', 15000)

  // Let app fully render
  await browser.wait(2500)

  // Open search dialog
  const open_search = await browser.evaluate(`const searchBtn = document.querySelector('[aria-label="Search"], button[class*="search"], a[href*="search"], [data-testid="search"]'); if (searchBtn) { searchBtn.click(); } else { document.dispatchEvent(new KeyboardEvent('keydown', { key: '/', code: 'Slash', keyCode: 191, bubbles: true })); } return { opened: true };`)

  // Wait for search dialog
  await browser.wait(1500)

  // Type search query
  const type_query = await browser.evaluate(`const input = document.querySelector('input[type="search"], input[placeholder*="Search"], input[placeholder*="search"], [role="combobox"], [data-testid="search-input"], dialog input, [class*="search"] input'); if (input) { input.focus(); input.value = ''; document.execCommand('insertText', false, '' + params.query + ''); input.dispatchEvent(new Event('input', { bubbles: true })); input.dispatchEvent(new Event('change', { bubbles: true })); } return { typed: !!input };`)

  // Wait for search results
  await browser.wait(3000)

  // Extract search results
  const search_results = await browser.evaluate(`const tasks = []; document.querySelectorAll('.task_list_item, [class*="task_list_item"], [data-testid="task"], [class*="search"] li, [class*="result"] [class*="task"]').forEach((el, i) => { if (i < 20) { const nameEl = el.querySelector('.task_content, [class*="task_content"], [data-testid="task-name"], [class*="content"]'); const dueEl = el.querySelector('.due_date, [class*="due"], time, [class*="date"]'); const prioEl = el.querySelector('[class*="priority"]'); tasks.push({ name: nameEl?.textContent?.trim() || '', due_date: dueEl?.textContent?.trim() || '', priority: prioEl?.className?.match(/priority_(\d)/)?.[1] || prioEl?.getAttribute('data-priority') || '' }); } }); return { query: '' + params.query + '', task_count: tasks.length, tasks: tasks.filter(t => t.name) };`)

  return search_results
}
